import json
from unittest import TestCase
from unittest.mock import MagicMock, patch
from opnsense_api.api.helper import Helper
from opnsense_api.client import Client
from opnsense_api.pydantic.Cert import Cert
from opnsense_api.pydantic.SearchResult import SearchResult, CertSearchResult


class TestPydanticCert(TestCase):


    @staticmethod
    def data_cert_search1():
        return """
{
  "rows": [
    {
      "uuid": "ce204f54-17d2-45a1-b3e3-7c5374eec5f8",
      "refid": "679dfa5a08e3a",
      "descr": "vpn.example.lan (ACME Client)",
      "caref": "679dfa5a00074",
      "%caref": "ExampleCA Intermediate CA 2025 (ACME Client)",
      "crt": "",
      "csr": "",
      "prv": "",
      "action": "reissue",
      "%action": "Reissue and replace certificate (does not restart services)",
      "key_type": "2048",
      "%key_type": "RSA-2048",
      "digest": "sha256",
      "%digest": "SHA256",
      "cert_type": "combined_server_client",
      "%cert_type": "Combined Client/Server Certificate",
      "lifetime": "397",
      "private_key_location": "firewall",
      "%private_key_location": "Save on this firewall",
      "city": "",
      "state": "",
      "organization": "",
      "organizationalunit": "",
      "country": "NL",
      "%country": "Netherlands",
      "email": "",
      "commonname": "vpn.example.lan",
      "ocsp_uri": "http://labca.example.lan/ocsp/",
      "altnames_dns": "vpn.example.lan",
      "altnames_ip": "",
      "altnames_uri": "",
      "altnames_email": "",
      "crt_payload": "-----BEGIN CERTIFICATE----------END CERTIFICATE-----",
      "csr_payload": "",
      "prv_payload": "-----BEGIN RSA PRIVATE KEY----------END RSA PRIVATE KEY-----",
      "rfc3280_purpose": "id-kp-serverAuth",
      "in_use": "1",
      "is_user": "0",
      "name": "/CN=vpn.example.lan",
      "valid_from": "1748818895",
      "valid_to": "1756594894"
    }
  ],
  "rowCount": 1,
  "total": 1,
  "current": 1
}
"""

    def test_load_cert_search_1(self):
        data = json.loads(self.data_cert_search1())
        cert_search = SearchResult.from_ui_dict(data, Cert) # type: CertSearchResult

        self.assertEqual(1, cert_search.rowCount)
        self.assertEqual(cert_search.rows[0].descr, "vpn.example.lan (ACME Client)")
        self.assertTrue(Helper.cert_expired(cert_search.rows[0]))

    def data_cert_search2(self):
        return """{"total":1,"rowCount":1,"current":1,"rows":[{"descr":"","refid":""}]}"""

    def data_cert_search3(self):
        return """{"total":1,"rowCount":1,"current":1,"rows":[{"descr":"test","refid":"ref"}]}"""

    @patch("requests.get")
    def test_load_cert_search_2(self, mock_get):
        mock_resp = MagicMock()
        mock_resp.text = self.data_cert_search2()
        mock_resp.status_code = 200
        mock_resp.headers = {"Content-Type": "application/json"}

        mock_get.return_value = mock_resp


        self.checker = Client(None, None, None, None)
        self.assertEqual(self.checker.trust_crl_search().rowCount, 0)
        mock_resp.text = self.data_cert_search3()
        self.assertEqual(self.checker.trust_crl_search().rowCount, 1)
